using Ledgerly.Domain.Common; using Ledgerly.Domain.Enums; using Ledgerly.Domain.Exceptions; using Ledgerly.Domain.ValueObjects; namespace Ledgerly.Domain.Entities; public sealed class Bill:OrganizationScopedEntity{ private readonly List<BillLine> _lines=new(); public Guid VendorId{get;private set;} public string BillNumber{get;private set;}=string.Empty; public DateOnly IssueDate{get;private set;} public DateOnly DueDate{get;private set;} public CurrencyCode Currency{get;private set;} public Guid ExpenseAccountId{get;private set;} public Guid PayableAccountId{get;private set;} public BillStatus Status{get;private set;} public Money Subtotal{get;private set;} public Money TaxTotal{get;private set;} public Money TotalAmount{get;private set;} public Money AmountPaid{get;private set;} public Guid? JournalEntryId{get;private set;} public IReadOnlyCollection<BillLine> Lines=>_lines.AsReadOnly(); private Bill(){Currency=new CurrencyCode("USD");Subtotal=TaxTotal=TotalAmount=AmountPaid=new Money(0m,Currency);} public Bill(Guid organizationId,Guid vendorId,string billNumber,DateOnly issueDate,DateOnly dueDate,CurrencyCode currency,Guid expenseAccountId,Guid payableAccountId):base(organizationId){ if(vendorId==Guid.Empty)throw new DomainException("Vendor is required."); VendorId=vendorId; BillNumber=billNumber.Trim(); IssueDate=issueDate; DueDate=dueDate; Currency=currency; ExpenseAccountId=expenseAccountId; PayableAccountId=payableAccountId; Subtotal=TaxTotal=TotalAmount=AmountPaid=new Money(0m,Currency); Status=BillStatus.Draft;} public BillLine AddLine(string description,decimal quantity,Money unitPrice,Guid? taxCodeId,Money discount){ if(Status!=BillStatus.Draft)throw new DomainException("Bill is not in draft status."); var line=new BillLine(Id,description,quantity,unitPrice,taxCodeId,discount); if(line.GetNetAmount().Amount<0m)throw new DomainException("Line discount cannot exceed line total."); _lines.Add(line); Touch(); return line;} public void Approve(IReadOnlyDictionary<Guid,TaxCode> taxCodes){ if(Status!=BillStatus.Draft)throw new DomainException("Bill is not in draft status."); if(_lines.Count==0)throw new DomainException("Bill must have at least one line before approval."); var amounts=CalculateAmounts(taxCodes); Subtotal=amounts.Subtotal; TaxTotal=amounts.Tax; TotalAmount=amounts.Total; Status=BillStatus.Approved; Touch();}
public void Approve(IReadOnlyDictionary<Guid,decimal> taxRates){ if(Status!=BillStatus.Draft)throw new DomainException("Bill is not in draft status."); if(_lines.Count==0)throw new DomainException("Bill must have at least one line before approval."); var amounts=CalculateAmounts(taxRates); Subtotal=amounts.Subtotal; TaxTotal=amounts.Tax; TotalAmount=amounts.Total; Status=BillStatus.Approved; Touch();} public void AttachJournalEntry(Guid journalEntryId){JournalEntryId=journalEntryId;Touch();} public void RecordPayment(Money paymentAmount){ if(Status!=BillStatus.Approved&&Status!=BillStatus.PartiallyPaid)throw new DomainException("Payments can only be recorded for approved or partially paid bills."); if(paymentAmount.Amount>(TotalAmount-AmountPaid).Amount)throw new DomainException("Payment amount exceeds balance due."); AmountPaid+=paymentAmount; Status=AmountPaid.Amount>=TotalAmount.Amount?BillStatus.Paid:BillStatus.PartiallyPaid; Touch();} public BillAmounts CalculateAmounts(IReadOnlyDictionary<Guid,TaxCode> taxCodes){ var zero=new Money(0m,Currency); var sub=zero; var tax=zero; foreach(var line in _lines){ sub+=line.GetNetAmount(); if(line.TaxCodeId is Guid id&&taxCodes.TryGetValue(id,out var tc)) tax+=line.GetTaxAmount(tc);} return new BillAmounts(sub,tax,sub+tax);}
public BillAmounts CalculateAmounts(IReadOnlyDictionary<Guid,decimal> taxRates){ var zero=new Money(0m,Currency); var sub=zero; var tax=zero; foreach(var line in _lines){ sub+=line.GetNetAmount(); if(line.TaxCodeId is Guid id&&taxRates.TryGetValue(id,out var rate)) tax+=line.GetTaxAmount(rate);} return new BillAmounts(sub,tax,sub+tax);} } public readonly record struct BillAmounts(Money Subtotal,Money Tax,Money Total);
